const item = $input.first();
const b = item.json.body || item.json;
const total = parseInt(String(b.total_tickets_enviados ?? '0'), 10) || 0;
const batch_id = `RND-${Date.now()}-${String(b.emp_legajo || 'X').replace(/[^a-zA-Z0-9_-]/g, '')}`;
const fechaEnvio = b.fecha_envio || new Date().toISOString();
const safeLegajo = String(b.emp_legajo || 'LEG').replace(/[^a-zA-Z0-9_-]/g, '_');
const safeNombre = String(b.emp_nombre || 'Nombre').replace(/[^a-zA-Z0-9áéíóúÁÉÍÓÚñÑ _-]/g, '').trim().replace(/\s+/g, '_');
const folder_safe_name = `${safeLegajo}_${safeNombre}`;
const parentId = item.json.drive_parent_folder_id;
if (!parentId) throw new Error('Completá drive_parent_folder_id en el nodo Variables — Config (carpeta raíz Rendiciones en Drive).');
const out = [];
for (let i = 0; i < total; i++) {
  const key = `ticket_foto_${i}`;
  const bin = item.binary?.[key];
  out.push({
    json: {
      batch_id,
      id_rendicion: `${batch_id}-T${i + 1}`,
      fecha_envio: fechaEnvio,
      emp_nombre: b.emp_nombre || '',
      emp_legajo: b.emp_legajo || '',
      motivo_rendicion: b.rendicion_motivo || '',
      ticket_indice: i + 1,
      ticket_categoria: b[`ticket_categoria_${i}`] ?? '',
      ticket_obs: b[`ticket_obs_${i}`] || '',
      folder_safe_name,
      drive_subfolder_name: folder_safe_name,
      drive_parent_folder_id: parentId
    },
    binary: bin ? { ticket_foto: bin } : {}
  });
}
if (!out.length) throw new Error('total_tickets_enviados inválido o 0 tickets.');
return out;

const first = $input.first();
if (!first?.json?.batch_id) throw new Error('batch_id faltante');
return [{
  json: {
    ok: true,
    batch_id: first.json.batch_id,
    mensaje: 'Recibido. Procesando comprobantes (Drive + IA); el gerente recibirá el mail de aprobación al terminar.',
    repo: 'https://github.com/jugauna/rendicion_de_gastos.git'
  }
}];

const all = $input.all();
if (!all.length) return [];
const first = all[0];
return [{ json: { ...first.json }, binary: first.binary }];

const primer = $('Code — Primer ítem (Drive)').first().json;
const rows = $input.all().filter((i) => i.json && i.json.id);
const folderRow = rows.find((i) => {
  const m = i.json.mimeType;
  return !m || m === 'application/vnd.google-apps.folder';
}) || rows[0];
if (folderRow && folderRow.json && folderRow.json.id) {
  return [{ json: { ...primer, empleado_subfolder_id: folderRow.json.id, _subcarpeta: 'encontrada' } }];
}
return [{ json: { ...primer, empleado_subfolder_id: null, _subcarpeta: 'crear' } }];

const created = $input.first().json;
const base = $('Code — Resolver subcarpeta (búsqueda)').first().json;
const id = created.id || created.folderId;
if (!id) throw new Error('Drive no devolvió id de carpeta creada.');
return [{ json: { ...base, empleado_subfolder_id: id, _subcarpeta: 'creada' } }];

const resolved = $input.first().json;
const id = resolved.empleado_subfolder_id;
if (!id) throw new Error('No se resolvió empleado_subfolder_id en Drive (buscar/crear).');
const all = $('Code — Expandir Tickets').all();
return all.map((i) => ({
  json: { ...i.json, empleado_subfolder_id: id },
  binary: i.binary
}));

const merged = $input.item.json;
const idx = $itemIndex;
const base = $('Code — Expandir Tickets').all()[idx].json;

const ocrRaw = merged.output ?? merged.text ?? '';
let ocr = { monto_total: null, moneda: '', fecha_factura: null, CUIT_proveedor: null };
try {
  const m = String(ocrRaw).match(/\{[\s\S]*\}/);
  if (m) ocr = { ...ocr, ...JSON.parse(m[0]) };
} catch (e) {}

function normalizeAmount(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;

  const s = String(v).trim();
  if (!s) return null;

  // Keep digits, dot, comma and minus. (Removes currency symbols and spaces.)
  let cleaned = s.replace(/[^\d,\.\-]/g, '');

  // If both separators exist, assume dot = thousands and comma = decimal.
  if (cleaned.includes(',') && cleaned.includes('.')) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else if (cleaned.includes(',')) {
    // If only comma exists, assume it's the decimal separator.
    cleaned = cleaned.replace(',', '.');
  }

  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : null;
}

function normalizeCuit(v) {
  if (v === null || v === undefined) return '';
  const s = String(v).replace(/[^\d]/g, '');
  return s || '';
}

const link = merged.webViewLink || merged.webContentLink || '';
const idFoto = merged.id || merged.fileId || '';
const monto = normalizeAmount(ocr.monto_total);

return {
  json: {
    ...base,
    id_foto_drive: idFoto,
    link_foto_drive: link,
    fecha_ticket_ia: ocr.fecha_factura || '',
    monto_total_ia: monto === null ? '' : monto,
    moneda_ia: ocr.moneda || '',
    cuit_proveedor_ia: normalizeCuit(ocr.CUIT_proveedor)
  }
};

const all = $input.all();
const j0 = all[0].json;
const ids = all.map(i => i.json.id_rendicion);
const monto_total = all.map(i => {
  const r = i.json;
  const parts = [r.monto_total_ia, r.moneda_ia].filter((v) => v !== null && v !== undefined && v !== '');
  return parts.join(' ').trim();
}).filter(Boolean).join(' · ') || '';
const link_foto_drive = j0.link_foto_drive || (all[0] && all[0].json.link_foto_drive) || '';
function ensureWebhookSuffix(resumeUrl, suffix) {
  if (!resumeUrl || !suffix) return resumeUrl;
  const s = String(suffix).replace(/^\/+|\/+$/g, '');
  if (resumeUrl.includes('/' + s + '?') || resumeUrl.includes('/' + s + '&') || resumeUrl.endsWith('/' + s)) return resumeUrl;
  const q = resumeUrl.indexOf('?');
  if (q === -1) return resumeUrl + '/' + s;
  return resumeUrl.slice(0, q) + '/' + s + resumeUrl.slice(q);
}
function appendDecision(resumeUrl, decision) {
  if (!resumeUrl) return '';
  const sep = resumeUrl.includes('?') ? '&' : '?';
  return resumeUrl + sep + 'decision=' + encodeURIComponent(decision);
}
const cfg = $('Variables — Config').first().json || {};
const waitSuffix = cfg.wait_webhook_suffix || 'aprobacion-gerente';
const ru = ensureWebhookSuffix($execution.resumeUrl || '', waitSuffix);
return [{
  json: {
    batch_id: j0.batch_id,
    id_rendiciones: ids,
    emp_nombre: j0.emp_nombre,
    emp_legajo: j0.emp_legajo,
    motivo_rendicion: j0.motivo_rendicion,
    fecha_envio: j0.fecha_envio,
    resumen_html: all.map(i => {
      const r = i.json;
      return `<li><strong>${r.ticket_categoria || ''}</strong> — ${r.monto_total_ia ?? ''} ${r.moneda_ia || ''} — <a href="${r.link_foto_drive || ''}" target="_blank">Foto Drive</a></li>`;
    }).join(''),
    link_primera_foto: link_foto_drive,
    link_foto_drive,
    monto_total,
    fecha_ticket_ia: j0.fecha_ticket_ia || '',
    cuit_proveedor_ia: j0.cuit_proveedor_ia || '',
    repo: 'https://github.com/jugauna/rendicion_de_gastos.git',
    resume_url_aprobar: appendDecision(ru, 'aprobar'),
    resume_url_rechazar: appendDecision(ru, 'rechazar')
  }
}];

const prev = $('Code — Batch email').first().json;
const ids = prev.id_rendiciones || [];
const webhook = $input.first().json;
const decision = webhook.query?.decision || webhook.body?.decision || webhook.decision || '';
const aprobada = decision === 'aprobar';
const estado = aprobada ? 'Aprobada' : 'Rechazada';
const fecha = new Date().toISOString();
return ids.map((id) => ({ json: { id_rendicion: id, Estado: estado, Fecha_Resolucion: fecha } }));

const rows = $input.all();
if (!rows.length) return [];
const estado = rows[0].json.Estado;
if (estado === 'Aprobada') {
  return [{ json: { _notificar_contable: true } }];
}
return [];
